import React, { useState, useEffect } from 'react';
import { useAuth } from '../context/AuthContext';
import { Users, Package, FileText, Activity, TrendingUp, AlertCircle, Clock } from 'lucide-react';
import api from '../services/api';

const AdminDashboard = () => {
    const { user } = useAuth();
    const [stats, setStats] = useState({
        totalEmployees: 0,
        totalInventory: 0,
        pendingOrders: 0,
        totalRevenue: 0
    });
    const [loading, setLoading] = useState(true);

    const fetchStats = async () => {
        try {
            const res = await api.get('/dashboard/admin');
            setStats(res.data);
        } catch (err) {
            console.error('Failed to fetch dashboard stats');
        } finally {
            setLoading(false);
        }
    };

    useEffect(() => {
        fetchStats();
    }, []);

    const statCards = [
        { name: 'Total Employees', value: stats.totalEmployees, icon: Users, color: 'bg-blue-50 text-blue-600', trend: '+2 new' },
        { name: 'Inventory Items', value: stats.totalInventory, icon: Package, color: 'bg-indigo-50 text-indigo-600', trend: 'Stocks ok' },
        { name: 'Pending Orders', value: stats.pendingOrders, icon: Activity, color: 'bg-amber-50 text-amber-600', trend: 'Needs action' },
        { name: 'Total Revenue', value: `₹${Number(stats.totalRevenue).toLocaleString()}`, icon: TrendingUp, color: 'bg-green-50 text-green-600', trend: 'All-time' },
    ];

    return (
        <div className="space-y-6">
            <div className="flex items-center justify-between pb-4 border-b border-slate-200">
                <div>
                    <h1 className="text-2xl font-black tracking-tight text-slate-900 uppercase italic">Admin Dashboard</h1>
                    <p className="text-sm text-slate-500 mt-1">Welcome back, <span className="font-bold text-blue-600 underline">{user?.name}</span>!</p>
                </div>
                <div className="hidden sm:block">
                    <button className="bg-slate-900 hover:bg-black text-white px-6 py-2.5 rounded-2xl text-xs font-black uppercase tracking-widest shadow-xl transition-all">
                        Company Report
                    </button>
                </div>
            </div>

            {/* Stats Grid */}
            <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-6">
                {statCards.map((stat) => {
                    const Icon = stat.icon;
                    return (
                        <div key={stat.name} className="bg-white p-6 rounded-3xl shadow-sm border border-slate-100 hover:shadow-2xl hover:-translate-y-1 transition-all duration-300">
                            <div className="flex items-center justify-between">
                                <p className="text-[10px] font-black uppercase tracking-widest text-slate-400">{stat.name}</p>
                                <div className={`p-2 rounded-xl ${stat.color}`}>
                                    <Icon className="h-5 w-5" />
                                </div>
                            </div>
                            <div className="mt-4 flex items-baseline justify-between">
                                <p className="text-2xl font-black text-slate-900">{loading ? '...' : stat.value}</p>
                                <span className="text-[10px] font-bold text-slate-400 bg-slate-50 px-2 py-1 rounded">
                                    {stat.trend}
                                </span>
                            </div>
                        </div>
                    );
                })}
            </div>

            <div className="grid grid-cols-1 lg:grid-cols-3 gap-6 mt-8">
                {/* Systems Status */}
                <div className="lg:col-span-2 bg-slate-900 p-8 rounded-[2rem] text-white overflow-hidden relative group">
                    <div className="absolute top-0 right-0 p-8 opacity-10 group-hover:scale-110 transition-transform">
                        <TrendingUp className="h-40 w-40" />
                    </div>
                    <h2 className="text-xl font-black uppercase tracking-wider mb-6">System Health & Operations</h2>
                    <div className="space-y-8 relative z-10">
                        <div className="flex gap-4">
                            <div className="h-12 w-12 bg-white/10 rounded-2xl flex items-center justify-center">
                                <AlertCircle className="h-6 w-6 text-blue-400" />
                            </div>
                            <div>
                                <h3 className="font-bold text-lg">Server Uptime</h3>
                                <p className="text-slate-400 text-sm">99.98% stable. Last backup 2 hours ago.</p>
                            </div>
                        </div>
                        <div className="flex gap-4">
                            <div className="h-12 w-12 bg-white/10 rounded-2xl flex items-center justify-center">
                                <Clock className="h-6 w-6 text-amber-400" />
                            </div>
                            <div>
                                <h3 className="font-bold text-lg">Daily Activity</h3>
                                <p className="text-slate-400 text-sm">Active employees currently online: 12</p>
                            </div>
                        </div>
                    </div>
                </div>

                {/* Quick Actions */}
                <div className="bg-white p-8 rounded-[2rem] border border-slate-100 shadow-sm flex flex-col justify-between">
                    <div>
                        <h2 className="text-xl font-black text-slate-900 mb-6">Management</h2>
                        <div className="space-y-3">
                            {['Add New Product', 'Create Invoice', 'Approve Orders'].map(act => (
                                <button key={act} className="w-full text-left p-4 rounded-2xl bg-slate-50 hover:bg-blue-50 text-slate-700 hover:text-blue-700 font-bold text-sm transition-all flex items-center justify-between border border-transparent hover:border-blue-100">
                                    {act} <FileText className="h-4 w-4 opacity-50" />
                                </button>
                            ))}
                        </div>
                    </div>
                    <div className="mt-8 p-4 bg-slate-50 rounded-2xl text-center">
                        <p className="text-[10px] font-bold text-slate-400 uppercase tracking-widest">Active Database</p>
                        <p className="text-xs font-bold text-slate-600 mt-1 italic">engineering_business_db</p>
                    </div>
                </div>
            </div>
        </div>
    );
};

export default AdminDashboard;

import React, { useState, useEffect } from 'react';
import api from '../services/api';
import { Package, Search, Filter, CheckCircle, XCircle, Clock, ExternalLink, Loader2, Download } from 'lucide-react';
import DetailModal from '../components/DetailModal';
import { generateInvoicePDF } from '../utils/invoiceGenerator';

const AdminOrders = () => {
    const [orders, setOrders] = useState([]);
    const [loading, setLoading] = useState(true);
    const [search, setSearch] = useState('');
    const [statusFilter, setStatusFilter] = useState('all');
    const [detailOrder, setDetailOrder] = useState(null);

    const fetchOrders = async () => {
        try {
            const res = await api.get('/orders');
            setOrders(res.data);
        } catch (err) {
            console.error('Failed to fetch orders');
        } finally {
            setLoading(false);
        }
    };

    useEffect(() => {
        fetchOrders();
    }, []);

    const handleUpdateStatus = async (id, newStatus) => {
        try {
            await api.patch(`/orders/${id}/status`, { status: newStatus });
            setOrders(orders.map(o => o.id === id ? { ...o, status: newStatus } : o));
        } catch (err) {
            alert('Failed to update status');
        }
    };

    const statusStyle = {
        'pending': 'bg-amber-100 text-amber-700',
        'approved': 'bg-blue-100 text-blue-700',
        'shipped': 'bg-indigo-100 text-indigo-700',
        'delivered': 'bg-green-100 text-green-700',
        'cancelled': 'bg-red-100 text-red-700',
    };

    const filtered = orders.filter(o => {
        const matchesSearch = o.order_number.toLowerCase().includes(search.toLowerCase()) || 
                              o.customer_name?.toLowerCase().includes(search.toLowerCase());
        const matchesStatus = statusFilter === 'all' || o.status === statusFilter;
        return matchesSearch && matchesStatus;
    });

    const openDetail = async (id) => {
        try {
            const res = await api.get(`/orders/${id}`);
            setDetailOrder({ ...res.data, invoice_number: res.data.order_number });
        } catch (err) {
            alert('Failed to load order details');
        }
    };

    const handleDownload = async (id) => {
        try {
            const res = await api.get(`/orders/${id}`);
            generateInvoicePDF({ ...res.data, invoice_number: res.data.order_number });
        } catch (err) {
            alert('Failed to generate PDF');
        }
    };

    return (
        <div className="space-y-6">
            <div className="pb-4 border-b border-slate-200">
                <h1 className="text-2xl font-bold text-slate-900">Order Management</h1>
                <p className="text-sm text-slate-500 mt-1">Review and process customer material requests.</p>
            </div>

            {/* Filters */}
            <div className="flex flex-col sm:flex-row gap-4">
                <div className="relative flex-1">
                    <Search className="absolute left-3 top-1/2 -translate-y-1/2 h-4 w-4 text-slate-400" />
                    <input 
                        type="text" 
                        placeholder="Search by order # or customer..." 
                        className="w-full pl-10 pr-4 py-2.5 bg-white border border-slate-200 rounded-xl text-sm focus:ring-2 focus:ring-blue-500 shadow-sm"
                        value={search}
                        onChange={e => setSearch(e.target.value)}
                    />
                </div>
                <div className="flex gap-2 p-1 bg-slate-100 rounded-xl">
                    {['all', 'pending', 'approved', 'shipped'].map(s => (
                        <button 
                            key={s}
                            onClick={() => setStatusFilter(s)}
                            className={`px-4 py-1.5 rounded-lg text-xs font-bold uppercase transition-all ${
                                statusFilter === s ? 'bg-white text-blue-600 shadow-sm' : 'text-slate-500 hover:text-slate-700'
                            }`}
                        >
                            {s}
                        </button>
                    ))}
                </div>
            </div>

            <div className="bg-white rounded-3xl shadow-sm border border-slate-100 overflow-hidden">
                {loading ? (
                    <div className="p-20 text-center text-slate-400">
                        <Loader2 className="h-8 w-8 animate-spin mx-auto mb-2 text-blue-500" />
                        <p>Syncing orders...</p>
                    </div>
                ) : filtered.length === 0 ? (
                    <div className="p-20 text-center">
                        <Clock className="h-12 w-12 text-slate-200 mx-auto mb-4" />
                        <p className="text-slate-500">No matching orders found.</p>
                    </div>
                ) : (
                    <div className="overflow-x-auto">
                        <table className="w-full text-sm">
                            <thead className="bg-slate-50 border-b border-slate-100">
                                <tr>
                                    <th className="text-left px-6 py-4 text-xs font-bold text-slate-400 uppercase tracking-widest">Order Info</th>
                                    <th className="text-left px-6 py-4 text-xs font-bold text-slate-400 uppercase tracking-widest">Customer</th>
                                    <th className="text-left px-6 py-4 text-xs font-bold text-slate-400 uppercase tracking-widest">Amount</th>
                                    <th className="text-left px-6 py-4 text-xs font-bold text-slate-400 uppercase tracking-widest">Status</th>
                                    <th className="text-left px-6 py-4 text-xs font-bold text-slate-400 uppercase tracking-widest">Action</th>
                                </tr>
                            </thead>
                            <tbody className="divide-y divide-slate-50">
                                {filtered.map(order => (
                                    <tr key={order.id} className="hover:bg-slate-50/50 transition-colors">
                                        <td className="px-6 py-5">
                                            <div className="flex flex-col">
                                                <span className="font-mono text-xs font-black text-blue-600">{order.order_number}</span>
                                                <span className="text-[10px] text-slate-400 mt-1">{new Date(order.created_at).toLocaleString()}</span>
                                            </div>
                                        </td>
                                        <td className="px-6 py-5">
                                            <div className="flex items-center gap-3">
                                                <div className="h-8 w-8 rounded-full bg-slate-100 flex items-center justify-center font-bold text-slate-500 text-xs">
                                                    {order.customer_name?.charAt(0)}
                                                </div>
                                                <div className="flex flex-col">
                                                    <span className="font-bold text-slate-800 leading-none">{order.customer_name}</span>
                                                    <span className="text-[10px] text-slate-400 mt-1">{order.customer_email}</span>
                                                </div>
                                            </div>
                                        </td>
                                        <td className="px-6 py-5 font-black text-slate-900">₹{Number(order.subtotal).toLocaleString()}</td>
                                        <td className="px-6 py-5">
                                            <span className={`px-2.5 py-1.5 rounded-full text-[10px] font-black uppercase tracking-widest ${statusStyle[order.status]}`}>
                                                {order.status}
                                            </span>
                                        </td>
                                        <td className="px-6 py-5">
                                            <div className="flex items-center gap-2">
                                                <button 
                                                    onClick={() => openDetail(order.id)}
                                                    className="p-2 bg-slate-50 text-slate-400 hover:text-blue-600 hover:bg-blue-50 rounded-lg transition-all"
                                                    title="View Details"
                                                >
                                                    <ExternalLink className="h-4 w-4" />
                                                </button>
                                                <button 
                                                    onClick={() => handleDownload(order.id)}
                                                    className="p-2 bg-slate-50 text-slate-400 hover:text-blue-600 hover:bg-blue-50 rounded-lg transition-all"
                                                    title="Download Order Copy"
                                                >
                                                    <Download className="h-4 w-4" />
                                                </button>
                                                {order.status === 'pending' && (
                                                    <button 
                                                        onClick={() => handleUpdateStatus(order.id, 'approved')}
                                                        className="p-2 bg-green-50 text-green-600 hover:bg-green-600 hover:text-white rounded-lg transition-all"
                                                        title="Approve Order"
                                                    >
                                                        <CheckCircle className="h-4 w-4" />
                                                    </button>
                                                )}
                                                {order.status !== 'cancelled' && (
                                                    <button 
                                                        onClick={() => handleUpdateStatus(order.id, 'cancelled')}
                                                        className="p-2 bg-red-50 text-red-400 hover:text-red-600 hover:bg-red-600 hover:text-white rounded-lg transition-all"
                                                        title="Cancel Order"
                                                    >
                                                        <XCircle className="h-4 w-4" />
                                                    </button>
                                                )}
                                            </div>
                                        </td>
                                    </tr>
                                ))}
                            </tbody>
                        </table>
                    </div>
                )}
            </div>

            <DetailModal 
                isOpen={!!detailOrder} 
                onClose={() => setDetailOrder(null)} 
                title={detailOrder ? `Order: ${detailOrder.order_number}` : ''}
                data={detailOrder}
                type="invoice"
            />
        </div>
    );
};

export default AdminOrders;

import React, { useState, useEffect } from 'react';
import api from '../services/api';
import { FileText, Plus, X, Trash2, Eye, CheckCircle, Clock, AlertCircle, Search, Download, ExternalLink } from 'lucide-react';
import { generateInvoicePDF } from '../utils/invoiceGenerator';
import DetailModal from '../components/DetailModal';


const statusStyle = {
    draft: 'bg-slate-100 text-slate-600',
    sent: 'bg-blue-100 text-blue-700',
    paid: 'bg-green-100 text-green-700',
    overdue: 'bg-red-100 text-red-700',
};

const emptyItem = { description: '', hsn_code: '', quantity: 1, unit_price: '', amount: 0 };
const emptyForm = {
    customer_name: '', customer_email: '', customer_address: '', customer_gstin: '',
    gst_rate: 18, due_date: '', notes: '', status: 'draft',
};

const BillingManagement = () => {
    const [invoices, setInvoices] = useState([]);
    const [inventory, setInventory] = useState([]);
    const [loading, setLoading] = useState(true);
    const [search, setSearch] = useState('');
    const [showModal, setShowModal] = useState(false);
    const [viewInvoice, setViewInvoice] = useState(null);
    const [detailInvoice, setDetailInvoice] = useState(null);
    const [form, setForm] = useState(emptyForm);
    const [items, setItems] = useState([{ ...emptyItem }]);
    const [submitting, setSubmitting] = useState(false);
    const [error, setError] = useState('');

    const fetchData = async () => {
        try {
            const [invRes, itemsRes] = await Promise.all([
                api.get('/invoices'),
                api.get('/inventory')
            ]);
            setInvoices(invRes.data);
            setInventory(itemsRes.data);
        } catch {
            setError('Failed to load data.');
        } finally {
            setLoading(false);
        }
    };

    useEffect(() => { fetchData(); }, []);

    const updateItem = (index, field, value) => {
        const updated = [...items];
        updated[index][field] = value;
        if (field === 'quantity' || field === 'unit_price') {
            updated[index].amount = (Number(updated[index].quantity) * Number(updated[index].unit_price)).toFixed(2);
        }
        setItems(updated);
    };

    const addItem = () => setItems([...items, { ...emptyItem }]);
    const removeItem = (i) => setItems(items.filter((_, idx) => idx !== i));

    const subtotal = items.reduce((sum, i) => sum + Number(i.amount), 0);
    const gstAmount = ((subtotal * Number(form.gst_rate)) / 100);
    const total = subtotal + gstAmount;

    const handleSubmit = async (e) => {
        e.preventDefault();
        setSubmitting(true); setError('');
        try {
            await api.post('/invoices', {
                ...form,
                subtotal: subtotal.toFixed(2),
                gst_amount: gstAmount.toFixed(2),
                total: total.toFixed(2),
                items,
            });
            await fetchData();
            setShowModal(false);
            setForm(emptyForm);
            setItems([{ ...emptyItem }]);
        } catch (err) {
            setError(err.response?.data?.message || 'Failed to create invoice.');
        } finally { setSubmitting(false); }
    };

    const handleDelete = async (id) => {
        if (!window.confirm('Delete this invoice?')) return;
        await api.delete(`/invoices/${id}`);
        setInvoices(prev => prev.filter(i => i.id !== id));
    };

    const handleDownload = async (id) => {
        try {
            const res = await api.get(`/invoices/${id}`);
            generateInvoicePDF(res.data);
        } catch (err) {
            alert('Failed to generate PDF');
        }
    };

    const handleStatusChange = async (id, status) => {
        await api.patch(`/invoices/${id}/status`, { status });
        setInvoices(prev => prev.map(i => i.id === id ? { ...i, status } : i));
    };

    const handleGenerateReport = async () => {
        try {
            const res = await api.get('/invoices/report');
            const csvData = res.data.map(row => `${row.month},${row.invoice_count},${row.revenue},${row.tax_collected}`).join('\n');
            const csvContent = "data:text/csv;charset=utf-8,Month,Invoice Count,Revenue,Tax Collected\n" + csvData;
            const encodedUri = encodeURI(csvContent);
            const link = document.createElement("a");
            link.setAttribute("href", encodedUri);
            link.setAttribute("download", `Revenue_Report_${new Date().toLocaleDateString()}.csv`);
            document.body.appendChild(link);
            link.click();
        } catch (err) {
            alert('Failed to generate report');
        }
    };

    const filtered = invoices.filter(i =>
        i.invoice_number?.toLowerCase().includes(search.toLowerCase()) ||
        i.customer_name?.toLowerCase().includes(search.toLowerCase())
    );

    const totalRevenue = invoices.filter(i => i.status === 'paid').reduce((sum, i) => sum + Number(i.total), 0);
    const pending = invoices.filter(i => i.status === 'sent' || i.status === 'draft').length;

    return (
        <div className="space-y-6">
            <div className="flex flex-col sm:flex-row sm:items-center justify-between gap-4 pb-4 border-b border-slate-200">
                <div>
                    <h1 className="text-2xl font-bold text-slate-900">Billing & Invoices</h1>
                    <p className="text-sm text-slate-500 mt-1">{invoices.length} invoices total</p>
                </div>
                <div className="flex items-center gap-3">
                    <button 
                        onClick={handleGenerateReport}
                        className="flex items-center gap-2 bg-white border border-slate-200 hover:bg-slate-50 text-slate-700 px-4 py-2.5 rounded-lg text-sm font-medium transition-colors shadow-sm"
                    >
                        <FileText className="h-4 w-4" /> Reports
                    </button>
                    <button 
                        onClick={() => setShowModal(true)} 
                        className="flex items-center gap-2 bg-blue-600 hover:bg-blue-700 text-white px-4 py-2.5 rounded-lg text-sm font-medium transition-colors shadow-sm"
                    >
                        <Plus className="h-4 w-4" /> New Invoice
                    </button>
                </div>
            </div>

            {/* Stats */}
            <div className="grid grid-cols-1 sm:grid-cols-3 gap-4">
                <div className="bg-white rounded-2xl p-5 border border-slate-100 shadow-sm">
                    <p className="text-sm text-slate-500">Total Collected</p>
                    <p className="text-2xl font-bold text-green-600 mt-1">₹{totalRevenue.toLocaleString('en-IN', {maximumFractionDigits:2})}</p>
                </div>
                <div className="bg-white rounded-2xl p-5 border border-slate-100 shadow-sm">
                    <p className="text-sm text-slate-500">Pending Invoices</p>
                    <p className="text-2xl font-bold text-amber-600 mt-1">{pending}</p>
                </div>
                <div className="bg-white rounded-2xl p-5 border border-slate-100 shadow-sm">
                    <p className="text-sm text-slate-500">Total Invoices</p>
                    <p className="text-2xl font-bold text-slate-800 mt-1">{invoices.length}</p>
                </div>
            </div>

            {/* Search */}
            <div className="relative max-w-sm">
                <Search className="absolute left-3 top-1/2 -translate-y-1/2 h-4 w-4 text-slate-400" />
                <input type="text" placeholder="Search invoices..." className="w-full pl-10 pr-4 py-2.5 border border-slate-200 rounded-lg text-sm focus:outline-none focus:ring-2 focus:ring-blue-500" value={search} onChange={e => setSearch(e.target.value)} />
            </div>

            {/* Table */}
            <div className="bg-white rounded-2xl shadow-sm border border-slate-100 overflow-hidden">
                {loading ? <div className="p-12 text-center text-slate-400">Loading...</div> :
                filtered.length === 0 ? (
                    <div className="p-12 text-center">
                        <FileText className="mx-auto h-10 w-10 text-slate-300 mb-3" />
                        <p className="text-slate-500 font-medium">No invoices yet. Create your first one!</p>
                    </div>
                ) : (
                    <div className="overflow-x-auto">
                        <table className="w-full text-sm">
                            <thead className="bg-slate-50 border-b border-slate-100">
                                <tr>
                                    {['Invoice #', 'Customer', 'Amount', 'GST', 'Total', 'Status', 'Date', 'Actions'].map(h => (
                                        <th key={h} className="text-left px-6 py-3 text-xs font-semibold text-slate-500 uppercase tracking-wider">{h}</th>
                                    ))}
                                </tr>
                            </thead>
                            <tbody className="divide-y divide-slate-50">
                                {filtered.map(inv => (
                                    <tr key={inv.id} className="hover:bg-slate-50/70 transition-colors">
                                        <td className="px-6 py-4 font-mono text-xs text-blue-600 font-semibold">{inv.invoice_number}</td>
                                        <td className="px-6 py-4">
                                            <p className="font-medium text-slate-800">{inv.customer_name}</p>
                                            <p className="text-xs text-slate-400">{inv.customer_email}</p>
                                        </td>
                                        <td className="px-6 py-4 text-slate-600">₹{Number(inv.subtotal).toLocaleString('en-IN')}</td>
                                        <td className="px-6 py-4 text-slate-500">₹{Number(inv.gst_amount).toLocaleString('en-IN')} ({inv.gst_rate}%)</td>
                                        <td className="px-6 py-4 font-bold text-slate-900">₹{Number(inv.total).toLocaleString('en-IN')}</td>
                                        <td className="px-6 py-4">
                                            <select value={inv.status} onChange={e => handleStatusChange(inv.id, e.target.value)} className={`text-xs font-semibold px-2.5 py-1 rounded-full border-0 cursor-pointer focus:outline-none ${statusStyle[inv.status]}`}>
                                                {['draft','sent','paid','overdue'].map(s => <option key={s} value={s}>{s.charAt(0).toUpperCase()+s.slice(1)}</option>)}
                                            </select>
                                        </td>
                                        <td className="px-6 py-4 text-slate-500 text-xs">{new Date(inv.created_at).toLocaleDateString('en-IN')}</td>
                                        <td className="px-6 py-4">
                                            <div className="flex gap-2">
                                                <button 
                                                    onClick={() => setDetailInvoice(inv)}
                                                    className="p-1.5 text-blue-600 hover:bg-blue-50 rounded-md transition-colors"
                                                    title="View Details"
